params.prompt:
(s) => {
  const historyText = (s.questionHistory ?? []).length > 0 ? '
已完成的问答：
' + (s.questionHistory ?? []).join('
---
') : '
开始第一轮提问。';
  return [new SystemMessage('你是技术面试官。基于面试策略、已回答的问题，提出下一个技术面试问题。必须遵守以下要求：
1. 从基础到深入层层递进
2. 如果上一回答有误则追问相关基础概念
3. 如果回答正确则提升难度或换新领域
4. 只输出问题本身，不要序号和评价
5. 问题要具体且有深度，不要泛泛而问'), new HumanMessage(`面试背景（岗位描述+简历）：${s.query}
${historyText}

当前是第${(s.questionCount ?? 0) + 1}个问题。请提出下一个技术面试问题。`)];
}

params.write:
(r, s) => {
  const p = (r.parsed ?? {}) as Record<string, unknown>;
  const score = String(p.score ?? 5);
  const feedback = String(p.feedback ?? '');
  const correctAnswer = String(p.correctAnswer ?? '');
  const shouldContinue = p.shouldContinue !== false;
  const entry = `【第${s.questionCount}题】得分：${score}/10\n反馈：${feedback}${correctAnswer ? '\n参考答案：' + correctAnswer : ''}`;
  return {
    scores: [score],
    questionHistory: [entry],
    currentFeedback: `**评分**：${score}/10\n\n${feedback}${correctAnswer ? '\n\n**参考答案**：' + correctAnswer : ''}`,
    phase: (!shouldContinue || (s.questionCount ?? 0) >= 8) ? 'complete' : 'questioning'
  };
}

params.prompt:
(s) => {
  const scores = (s.scores ?? []).join(', ');
  const history = (s.questionHistory ?? []).join('
---
');
  return [new SystemMessage('你基于面试记录生成详细的能力评估报告。报告必须包括以下结构：
### 1. 面试概览
- 考察领域、问题数量、整体表现
### 2. 各领域能力评分（表格）
### 3. 优势与待改进项
### 4. 综合评级：A(卓越)/B(良好)/C(一般)/D(待加强)
### 5. 录用建议与后续面试建议
### 6. 技术深度与广度评估'), new HumanMessage(`岗位描述与简历：${s.query}

各题得分：${scores}

面试记录：
${history}`)];
}
